// Speed control for streaming video (e.g. Prime Video)
// Run this snippet after the video has loaded.
//
// Usage:
//   - Press D to increase speed by 0.1
//   - Press S to decrease speed by 0.1
//   - Use ss(rate) in the console to set a specific speed
//     Examples: ss(1.7), ss(2), ss(1) to reset to normal
//
// A temporary overlay in the top-left corner shows the current speed
// for 2 seconds whenever it changes.
// The X-Ray panel is automatically removed on run.

// --- Remove X-Ray overlay ---
// Removes the Prime Video X-Ray cast/trivia panel from the DOM entirely.
// document.querySelectorAll('.xrayQuickView, .xrayQuickViewList, [class*="xray"]').forEach(el => el.remove());

// --- Track current rate ourselves to avoid floating point issues ---
let currentRate = 1.0;

// --- Overlay setup ---
// Creates a fixed overlay element in the top-left corner of the page.
// Hidden by default; shown briefly whenever the speed changes.
const overlay = document.createElement('div');
Object.assign(overlay.style, {
  position: 'fixed',
  top: '20px',
  left: '20px',
  background: 'rgba(0, 0, 0, 0.7)',
  color: 'white',
  padding: '8px 14px',
  borderRadius: '6px',
  fontSize: '16px',
  fontFamily: 'monospace',
  zIndex: '999999',
  opacity: '0',
  transition: 'opacity 0.3s ease',
  pointerEvents: 'none', // don't interfere with clicks
});
document.body.appendChild(overlay);

// Timer reference for hiding the overlay after 2 seconds
let overlayTimeout = null;

// --- Show overlay briefly ---
// Displays the current speed in the overlay, then fades it out after 2 seconds.
function showOverlay(text) {
  overlay.textContent = text;
  overlay.style.opacity = '1';
  clearTimeout(overlayTimeout);
  overlayTimeout = setTimeout(() => {
    overlay.style.opacity = '0';
  }, 2000);
}

// --- Set speed ---
// Sets playback rate on all video elements and shows the overlay.
// Updates our internal tracker to avoid floating point drift.
function ss(rate) {
  // Clamp speed to a reasonable range (0.1 to 16)
  rate = Math.min(16, Math.max(0.1, rate));
  // Round to 1 decimal place to avoid floating point drift
  rate = Math.round(rate * 10) / 10;
  currentRate = rate;
  document.querySelectorAll('video').forEach(v => v.playbackRate = rate);
  showOverlay(`${rate.toFixed(1)}x`);
  console.log(`Speed set to ${rate}x`);
}

// --- Keyboard shortcuts ---
// Listens for 'S' (decrease by 0.1) and 'D' (increase by 0.1).
// Ignored when typing in input fields, textareas, etc.
document.addEventListener('keydown', (e) => {
  // Don't trigger when typing in input fields or textareas
  const tag = e.target.tagName.toLowerCase();
  if (tag === 'input' || tag === 'textarea' || e.target.isContentEditable) return;

  if (e.key === 'd' || e.key === 'D') {
    ss(currentRate + 0.1);
  } else if (e.key === 's' || e.key === 'S') {
    ss(currentRate - 0.1);
  }
});

// Set default speed on run
ss(1.0);

// Comprehensive Resource Analyzer
// Run this in the console of the page you want to analyze
// Make sure you're logged-in before you run the analyzer
(async function analyzePageResources() {
	console.clear();
	console.log("🔍 COMPREHENSIVE PAGE RESOURCE ANALYSIS");
	console.log("=".repeat(60));

	// 1. Performance API resources
	const perfResources = performance.getEntriesByType("resource");

	// 2. Better categorization
	const categories = {
		css: [],
		js: [],
		fonts: [],
		fontCss: [], // Google Fonts CSS links
		images: [],
		svg: [],
		api: [],
		other: [],
	};

	perfResources.forEach((r) => {
		const url = r.name.toLowerCase();

		if (url.includes("fonts.googleapis.com")) {
			categories.fontCss.push(r.name);
		} else if (
			url.includes("fonts.gstatic.com") ||
			url.match(/\.(woff2?|ttf|otf|eot)/)
		) {
			categories.fonts.push(r.name);
		} else if (url.includes(".css")) {
			categories.css.push(r.name);
		} else if (
			url.includes(".js") &&
			!url.includes("gtm.js") &&
			!url.includes("analytics")
		) {
			categories.js.push(r.name);
		} else if (url.match(/\.(png|jpg|jpeg|gif|webp|ico|avif)(\?|$)/)) {
			categories.images.push(r.name);
		} else if (url.includes(".svg")) {
			categories.svg.push(r.name);
		} else if (url.includes("/api/")) {
			categories.api.push(r.name);
		} else if (!url.includes("gtm.js") && !url.includes("googletagmanager")) {
			categories.other.push(r.name);
		}
	});

	// 3. Check document.fonts API for loaded fonts
	const loadedFonts = [];
	if (document.fonts) {
		document.fonts.forEach((font) => {
			loadedFonts.push({
				family: font.family,
				weight: font.weight,
				style: font.style,
				status: font.status,
			});
		});
	}

	// 4. Find fonts from stylesheets
	const fontFacesInCSS = [];
	try {
		for (const sheet of document.styleSheets) {
			try {
				for (const rule of sheet.cssRules || []) {
					if (rule instanceof CSSFontFaceRule) {
						fontFacesInCSS.push({
							family: rule.style.fontFamily,
							src: rule.style.src,
						});
					}
				}
			} catch (e) {
				/* CORS blocked stylesheet */
			}
		}
	} catch (e) {}

	// 5. Find inline SVGs
	const inlineSvgs = document.querySelectorAll("svg");
	const svgInfo = {
		count: inlineSvgs.length,
		unique: new Set(),
	};
	inlineSvgs.forEach((svg) => {
		// Get a simplified identifier
		const id =
			svg.getAttribute("data-slot") ||
			svg.getAttribute("class")?.split(" ")[0] ||
			svg.innerHTML.substring(0, 50);
		svgInfo.unique.add(id);
	});

	// 6. Find all images in DOM (including background images)
	const domImages = new Set();

	// Regular img tags
	document.querySelectorAll("img").forEach((img) => {
		if (img.src) domImages.add(img.src);
		if (img.srcset) domImages.add(`srcset: ${img.srcset}`);
	});

	// Background images in computed styles
	document.querySelectorAll("*").forEach((el) => {
		const bg = getComputedStyle(el).backgroundImage;
		if (bg && bg !== "none" && bg.includes("url(")) {
			domImages.add(bg);
		}
	});

	// 7. Check link tags for more resources
	const linkTags = {
		stylesheets: [],
		preconnect: [],
		icons: [],
		other: [],
	};
	document.querySelectorAll("link").forEach((link) => {
		const href = link.href;
		const rel = link.rel;
		if (rel === "stylesheet") linkTags.stylesheets.push(href);
		else if (rel === "preconnect") linkTags.preconnect.push(href);
		else if (rel === "icon" || rel === "apple-touch-icon")
			linkTags.icons.push(href);
		else if (href) linkTags.other.push({ rel, href });
	});

	// 8. Parse Google Fonts CSS to find actual font files
	let googleFontFiles = [];
	for (const fontCssUrl of categories.fontCss) {
		try {
			const response = await fetch(fontCssUrl);
			const css = await response.text();
			const fontUrls =
				css.match(/url\((https:\/\/fonts\.gstatic\.com[^)]+)\)/g) || [];
			googleFontFiles = fontUrls.map((u) =>
				u.replace("url(", "").replace(")", ""),
			);
		} catch (e) {
			console.log("Could not fetch Google Fonts CSS:", e);
		}
	}

	// PRINT RESULTS
	console.log("\n" + "=".repeat(60));
	console.log("📊 NETWORK RESOURCES (from Performance API)");
	console.log("=".repeat(60));

	console.log(`\n🎨 CSS FILES (${categories.css.length}):`);
	categories.css.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n🔤 GOOGLE FONTS CSS (${categories.fontCss.length}):`);
	categories.fontCss.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n📜 JS FILES (${categories.js.length}):`);
	categories.js.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n🖼️ IMAGES (${categories.images.length}):`);
	categories.images.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n🎯 SVG FILES (${categories.svg.length}):`);
	categories.svg.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n🔗 API CALLS (${categories.api.length}):`);
	categories.api.forEach((u) => console.log(`  ✓ ${u}`));

	console.log("\n" + "=".repeat(60));
	console.log("🔤 FONT ANALYSIS");
	console.log("=".repeat(60));

	console.log(
		`\n📥 Font files loaded via network (${categories.fonts.length}):`,
	);
	categories.fonts.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(
		`\n📥 Font files from Google Fonts CSS (${googleFontFiles.length}):`,
	);
	googleFontFiles.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(
		`\n🖥️ Fonts registered in document.fonts (${loadedFonts.length}):`,
	);
	const uniqueFamilies = [...new Set(loadedFonts.map((f) => f.family))];
	uniqueFamilies.forEach((family) => {
		const variants = loadedFonts.filter((f) => f.family === family);
		console.log(`  ✓ ${family} (${variants.length} variants)`);
	});

	console.log("\n" + "=".repeat(60));
	console.log("🎨 DOM ANALYSIS");
	console.log("=".repeat(60));

	console.log(
		`\n🔷 Inline SVGs: ${svgInfo.count} total (${svgInfo.unique.size} unique patterns)`,
	);

	console.log(`\n🖼️ Images in DOM (${domImages.size}):`);
	domImages.forEach((u) => console.log(`  ✓ ${u}`));

	console.log(`\n🔗 Link tags - Icons (${linkTags.icons.length}):`);
	linkTags.icons.forEach((u) => console.log(`  ✓ ${u}`));

	console.log("\n" + "=".repeat(60));
	console.log("📋 SUMMARY - WHAT NEEDS TO BE DOWNLOADED");
	console.log("=".repeat(60));

	const totalAssets = {
		"CSS files": categories.css.length,
		"Google Fonts CSS": categories.fontCss.length,
		"Font files (woff2)": googleFontFiles.length,
		"JS files": categories.js.length,
		"External images": categories.images.length,
		"External SVGs": categories.svg.length,
		"Inline SVGs": svgInfo.count,
		"Favicons/Icons": linkTags.icons.length,
	};

	console.log("\n");
	Object.entries(totalAssets).forEach(([key, val]) => {
		const status = val > 0 ? "✓" : "⚠️";
		console.log(`  ${status} ${key}: ${val}`);
	});

	// What extension captured vs what exists
	console.log("\n" + "=".repeat(60));
	console.log("🔴 EXTENSION GAP ANALYSIS");
	console.log("=".repeat(60));
	console.log("\nExtension captured:");
	console.log("  - 2 CSS files");
	console.log("  - 1 JS file");
	console.log("  - 2 images");
	console.log("  - 0 font files");
	console.log("\nMissing:");
	console.log(`  - ${googleFontFiles.length} font files (woff2)`);
	console.log(
		`  - ${svgInfo.count} inline SVGs (need to be preserved in HTML)`,
	);

	// Return data for export
	return {
		categories,
		googleFontFiles,
		loadedFonts,
		inlineSvgCount: svgInfo.count,
		domImages: [...domImages],
		linkTags,
	};
})();

/*
========================================
Advanced Web Page Inspector & Diagnostic Tool
A comprehensive analysis tool for modern web pages
Designed to reveal DOM structure, frameworks, components, and technical details
========================================
*/

class WebPageInspector {
  constructor() {
    this.results = {
      timestamp: new Date().toISOString(),
      url: window.location.href,
      userAgent: navigator.userAgent,
      viewport: {
        width: window.innerWidth,
        height: window.innerHeight,
      },
      analysis: {},
    };

    this.startTime = performance.now();
  }

  // Main analysis orchestrator
  async runFullAnalysis() {
    console.log("🚀 Starting Advanced Web Page Analysis...");
    console.log("================================================");

    try {
      // Core DOM analysis
      await this.analyzePageStructure();
      await this.analyzeFrameworks();
      await this.analyzeWebComponents();
      await this.analyzeShadowDOM();
      await this.analyzeIframes();
      await this.analyzeScripts();
      await this.analyzeStylesheets();
      await this.analyzeMetadata();
      await this.analyzeSecurity();
      await this.analyzePerformance();
      await this.analyzeAccessibility();
      await this.analyzeDynamicContent();
      await this.analyzeEventListeners();
      await this.analyzeStorage();
      await this.analyzeNetwork();

      // Summary and recommendations
      this.generateSummary();
      this.generateRecommendations();

      const endTime = performance.now();
      console.log(
        `\n⏱️ Analysis completed in ${(endTime - this.startTime).toFixed(2)}ms`,
      );

      return this.results;
    } catch (error) {
      console.error("❌ Analysis failed:", error);
      return { error: error.message, partialResults: this.results };
    }
  }

  // 1. Page Structure Analysis
  async analyzePageStructure() {
    console.log("\n📋 ANALYZING PAGE STRUCTURE");
    console.log("============================");

    const structure = {
      doctype: document.doctype ? document.doctype.name : "None",
      documentElement: document.documentElement.tagName,
      head: {
        title: document.title || "No title",
        metaCount: document.querySelectorAll("meta").length,
        linkCount: document.querySelectorAll("link").length,
        scriptCount: document.querySelectorAll("head script").length,
      },
      body: {
        id: document.body.id || "No ID",
        classes: [...document.body.classList],
        childElementCount: document.body.childElementCount,
        totalElements: document.querySelectorAll("*").length,
      },
      semanticElements: this.countSemanticElements(),
      customElements: this.findCustomElements(),
      dataAttributes: this.analyzeDataAttributes(),
    };

    console.log("Document Type:", structure.doctype);
    console.log("Total Elements:", structure.body.totalElements);
    console.log("Body Classes:", structure.body.classes);
    console.log("Custom Elements Found:", structure.customElements.length);
    console.log("Semantic Elements:", structure.semanticElements);

    this.results.analysis.structure = structure;
  }

  countSemanticElements() {
    const semanticTags = [
      "header",
      "nav",
      "main",
      "article",
      "section",
      "aside",
      "footer",
      "figure",
      "figcaption",
      "details",
      "summary",
    ];
    const counts = {};

    semanticTags.forEach((tag) => {
      counts[tag] = document.querySelectorAll(tag).length;
    });

    return counts;
  }

  findCustomElements() {
    const allElements = document.querySelectorAll("*");
    const customElements = [];
    const standardTags = new Set([
      "DIV",
      "SPAN",
      "P",
      "A",
      "IMG",
      "H1",
      "H2",
      "H3",
      "H4",
      "H5",
      "H6",
      "UL",
      "OL",
      "LI",
      "HEADER",
      "FOOTER",
      "NAV",
      "MAIN",
      "SECTION",
      "ARTICLE",
      "ASIDE",
      "BUTTON",
      "INPUT",
      "FORM",
      "TABLE",
      "TR",
      "TD",
      "TH",
      "TBODY",
      "THEAD",
      "SCRIPT",
      "STYLE",
      "LINK",
      "META",
      "TITLE",
      "HTML",
      "HEAD",
      "BODY",
    ]);

    allElements.forEach((el) => {
      if (!standardTags.has(el.tagName) && el.tagName.includes("-")) {
        customElements.push({
          tagName: el.tagName,
          id: el.id,
          classes: [...el.classList],
          attributes: [...el.attributes].map(
            (attr) =>
              `${attr.name}="${attr.value.substring(0, 50)}${attr.value.length > 50 ? "..." : ""}"`,
          ),
          hasShadowRoot: !!el.shadowRoot,
          innerHTML:
            el.innerHTML.substring(0, 200) +
            (el.innerHTML.length > 200 ? "..." : ""),
        });
      }
    });

    return customElements;
  }

  analyzeDataAttributes() {
    const allElements = document.querySelectorAll("*");
    const dataAttributes = new Set();

    allElements.forEach((el) => {
      [...el.attributes].forEach((attr) => {
        if (attr.name.startsWith("data-")) {
          dataAttributes.add(attr.name);
        }
      });
    });

    return {
      uniqueDataAttributes: [...dataAttributes],
      count: dataAttributes.size,
    };
  }

  // 2. Framework Detection
  async analyzeFrameworks() {
    console.log("\n🏗️ ANALYZING FRAMEWORKS & LIBRARIES");
    console.log("===================================");

    const frameworks = {
      detected: [],
      indicators: {},
      globalObjects: this.checkGlobalObjects(),
      cssFrameworks: this.detectCSSFrameworks(),
      buildTools: this.detectBuildTools(),
    };

    // Framework detection patterns
    const detectionPatterns = {
      React: () =>
        window.React ||
        document.querySelector("[data-reactroot]") ||
        document.querySelector("[data-react-helmet]"),
      "Vue.js": () =>
        window.Vue ||
        document.querySelector("[data-v-]") ||
        document.querySelector("[v-]"),
      Angular: () =>
        window.ng ||
        document.querySelector("[ng-]") ||
        document.querySelector("[data-ng-]"),
      "Nuxt.js": () => window.__NUXT__ || document.querySelector("#__nuxt"),
      "Next.js": () =>
        window.__NEXT_DATA__ || document.querySelector("#__next"),
      jQuery: () => window.jQuery || window.$,
      Lit: () => window.lit || document.querySelector("[data-lit]"),
      "Alpine.js": () => window.Alpine || document.querySelector("[x-data]"),
      Svelte: () => document.querySelector("[svelte-]"),
      "Ember.js": () => window.Ember || document.querySelector("[data-ember-]"),
      "Backbone.js": () => window.Backbone,
      "D3.js": () => window.d3,
      "Three.js": () => window.THREE,
      GSAP: () => window.gsap || window.TweenMax,
      "Chart.js": () => window.Chart,
      Lodash: () => window._ && window._.VERSION,
      "Moment.js": () => window.moment,
      Bootstrap: () =>
        window.bootstrap ||
        document.querySelector(".bootstrap") ||
        document.querySelector('[class*="bs-"]'),
      "Tailwind CSS": () =>
        document.querySelector('[class*="bg-"]') &&
        document.querySelector('[class*="text-"]'),
      "Material-UI": () =>
        window.MaterialUI || document.querySelector('[class*="Mui"]'),
      "Ant Design": () =>
        window.antd || document.querySelector('[class*="ant-"]'),
    };

    Object.entries(detectionPatterns).forEach(([name, detector]) => {
      try {
        const detected = detector();
        if (detected) {
          frameworks.detected.push(name);
          frameworks.indicators[name] =
            typeof detected === "object"
              ? "Object detected"
              : detected.toString().substring(0, 100);
        }
      } catch (e) {
        // Silent fail for framework detection
      }
    });

    console.log("Detected Frameworks:", frameworks.detected);
    console.log("CSS Frameworks:", frameworks.cssFrameworks);
    console.log("Global Objects:", Object.keys(frameworks.globalObjects));

    this.results.analysis.frameworks = frameworks;
  }

  checkGlobalObjects() {
    const commonGlobals = [
      "React",
      "Vue",
      "Angular",
      "jQuery",
      "$",
      "gsap",
      "d3",
      "THREE",
      "Chart",
      "_",
      "moment",
      "axios",
      "fetch",
    ];
    const detected = {};

    commonGlobals.forEach((obj) => {
      if (window[obj]) {
        detected[obj] = {
          type: typeof window[obj],
          version: window[obj].version || window[obj].VERSION || "Unknown",
          properties: Object.keys(window[obj]).slice(0, 10),
        };
      }
    });

    return detected;
  }

  detectCSSFrameworks() {
    const frameworks = [];
    const stylesheets = [...document.styleSheets];

    // Check for CSS framework indicators in classes
    const allElements = document.querySelectorAll("*");
    const classPatterns = {
      Bootstrap: /\b(container|row|col-|btn-|card-|navbar-|modal-)\w*/,
      "Tailwind CSS": /\b(bg-|text-|p-|m-|flex|grid|w-|h-)\w*/,
      Bulma: /\b(is-|has-|column|level|hero|navbar)\w*/,
      Foundation: /\b(foundation|grid-|cell|callout)\w*/,
      Materialize: /\b(materialize|btn|card|collection)\w*/,
      "Semantic UI": /\b(ui |semantic|button|menu|dropdown)\w*/,
      "Material-UI": /\b(Mui|makeStyles|withStyles)\w*/,
      "Ant Design": /\bant-\w*/,
    };

    Object.entries(classPatterns).forEach(([framework, pattern]) => {
      let found = false;
      for (let el of allElements) {
        if (pattern.test(el.className)) {
          found = true;
          break;
        }
      }
      if (found) frameworks.push(framework);
    });

    return frameworks;
  }

  detectBuildTools() {
    const indicators = [];

    // Check for build tool indicators
    if (document.querySelector('script[src*="webpack"]'))
      indicators.push("Webpack");
    if (document.querySelector('script[src*="vite"]')) indicators.push("Vite");
    if (document.querySelector('script[src*="parcel"]'))
      indicators.push("Parcel");
    if (window.__webpack_require__) indicators.push("Webpack (runtime)");
    if (window.__vite__) indicators.push("Vite (runtime)");

    return indicators;
  }

  // 3. Web Components Analysis
  async analyzeWebComponents() {
    console.log("\n🧩 ANALYZING WEB COMPONENTS");
    console.log("============================");

    const components = {
      customElements: [],
      shadowRoots: [],
      autonomousElements: [],
      customizedBuiltIns: [],
    };

    // Find all custom elements
    const allElements = document.querySelectorAll("*");

    allElements.forEach((el) => {
      // Check if it's a custom element (contains hyphen)
      if (el.tagName.includes("-")) {
        const componentInfo = {
          tagName: el.tagName,
          id: el.id,
          classes: [...el.classList],
          attributes: [...el.attributes].map((attr) => ({
            name: attr.name,
            value:
              attr.value.length > 100
                ? attr.value.substring(0, 100) + "..."
                : attr.value,
          })),
          hasShadowRoot: !!el.shadowRoot,
          shadowRootMode: el.shadowRoot ? el.shadowRoot.mode : null,
          innerHTML:
            el.innerHTML.substring(0, 300) +
            (el.innerHTML.length > 300 ? "..." : ""),
          computedStyle: {
            display: getComputedStyle(el).display,
            position: getComputedStyle(el).position,
            width: getComputedStyle(el).width,
            height: getComputedStyle(el).height,
          },
          customProperties: this.getCustomElementProperties(el),
          events: this.getElementEventListeners(el),
        };

        components.customElements.push(componentInfo);

        // Analyze shadow root if present
        if (el.shadowRoot) {
          components.shadowRoots.push(
            this.analyzeShadowRoot(el, el.shadowRoot),
          );
        }
      }
    });

    console.log("Custom Elements Found:", components.customElements.length);
    console.log("Shadow Roots Found:", components.shadowRoots.length);

    components.customElements.forEach((comp) => {
      console.log(
        `  - ${comp.tagName}: ${comp.hasShadowRoot ? "Has Shadow DOM" : "No Shadow DOM"}`,
      );
    });

    this.results.analysis.webComponents = components;
  }

  getCustomElementProperties(element) {
    const props = {};
    const allProps = Object.getOwnPropertyNames(element);

    // Filter out standard DOM properties
    const standardProps = [
      "id",
      "className",
      "innerHTML",
      "outerHTML",
      "tagName",
      "nodeName",
      "nodeType",
    ];
    const customProps = allProps.filter(
      (prop) =>
        !prop.startsWith("_") &&
        !standardProps.includes(prop) &&
        typeof element[prop] !== "function",
    );

    customProps.forEach((prop) => {
      try {
        const value = element[prop];
        props[prop] = {
          type: typeof value,
          value:
            typeof value === "object"
              ? "[Object]"
              : String(value).substring(0, 100),
        };
      } catch (e) {
        props[prop] = { type: "unknown", value: "Access denied" };
      }
    });

    return props;
  }

  // 4. Shadow DOM Deep Analysis
  async analyzeShadowDOM() {
    console.log("\n🌑 ANALYZING SHADOW DOM");
    console.log("=======================");

    const shadowAnalysis = {
      shadowRoots: [],
      totalShadowElements: 0,
      shadowStyles: [],
      shadowScripts: [],
    };

    // Find all elements with shadow roots
    const allElements = document.querySelectorAll("*");

    allElements.forEach((el) => {
      if (el.shadowRoot) {
        const analysis = this.analyzeShadowRoot(el, el.shadowRoot);
        shadowAnalysis.shadowRoots.push(analysis);
        shadowAnalysis.totalShadowElements += analysis.elementCount;
      }
    });

    console.log("Shadow Roots Found:", shadowAnalysis.shadowRoots.length);
    console.log("Total Shadow Elements:", shadowAnalysis.totalShadowElements);

    this.results.analysis.shadowDOM = shadowAnalysis;
  }

  analyzeShadowRoot(hostElement, shadowRoot) {
    const analysis = {
      host: {
        tagName: hostElement.tagName,
        id: hostElement.id,
        classes: [...hostElement.classList],
      },
      mode: shadowRoot.mode,
      elementCount: shadowRoot.querySelectorAll("*").length,
      innerHTML:
        shadowRoot.innerHTML.substring(0, 500) +
        (shadowRoot.innerHTML.length > 500 ? "..." : ""),
      styles: [],
      scripts: [],
      elements: {},
      customElements: [],
      eventListeners: [],
    };

    // Analyze styles in shadow DOM
    const shadowStyles = shadowRoot.querySelectorAll("style");
    shadowStyles.forEach((style, index) => {
      analysis.styles.push({
        index,
        content:
          style.textContent.substring(0, 200) +
          (style.textContent.length > 200 ? "..." : ""),
        length: style.textContent.length,
      });
    });

    // Analyze scripts in shadow DOM
    const shadowScripts = shadowRoot.querySelectorAll("script");
    shadowScripts.forEach((script, index) => {
      analysis.scripts.push({
        index,
        src: script.src || "inline",
        content:
          script.textContent.substring(0, 200) +
          (script.textContent.length > 200 ? "..." : ""),
        length: script.textContent.length,
      });
    });

    // Count element types in shadow DOM
    const shadowElements = shadowRoot.querySelectorAll("*");
    shadowElements.forEach((el) => {
      const tagName = el.tagName.toLowerCase();
      analysis.elements[tagName] = (analysis.elements[tagName] || 0) + 1;

      // Check for nested custom elements
      if (tagName.includes("-")) {
        analysis.customElements.push({
          tagName: el.tagName,
          classes: [...el.classList],
          attributes: [...el.attributes].map(
            (attr) => `${attr.name}="${attr.value}"`,
          ),
        });
      }
    });

    return analysis;
  }

  // 5. Iframe Analysis
  async analyzeIframes() {
    console.log("\n🖼️ ANALYZING IFRAMES");
    console.log("====================");

    const iframes = [...document.querySelectorAll("iframe")];
    const analysis = {
      count: iframes.length,
      details: [],
    };

    iframes.forEach((iframe, index) => {
      const detail = {
        index,
        src: iframe.src,
        id: iframe.id,
        name: iframe.name,
        classes: [...iframe.classList],
        attributes: [...iframe.attributes].map(
          (attr) => `${attr.name}="${attr.value}"`,
        ),
        dimensions: {
          width: iframe.width || getComputedStyle(iframe).width,
          height: iframe.height || getComputedStyle(iframe).height,
        },
        loading: iframe.loading,
        sandbox: iframe.sandbox.toString(),
        allowfullscreen: iframe.allowFullscreen,
        contentAccessible: false,
      };

      // Try to access iframe content (will fail for cross-origin)
      try {
        detail.contentDocument = !!iframe.contentDocument;
        detail.contentWindow = !!iframe.contentWindow;
        if (iframe.contentDocument) {
          detail.contentTitle = iframe.contentDocument.title;
          detail.contentURL = iframe.contentDocument.location.href;
          detail.contentAccessible = true;
        }
      } catch (e) {
        detail.crossOrigin = true;
        detail.accessError = e.message;
      }

      analysis.details.push(detail);
    });

    console.log("Iframes Found:", analysis.count);
    analysis.details.forEach((detail) => {
      console.log(
        `  - ${detail.src || "No src"}: ${detail.classes.join(" ")} (${detail.contentAccessible ? "Accessible" : "Cross-origin"})`,
      );
    });

    this.results.analysis.iframes = analysis;
  }

  // 6. Scripts Analysis
  async analyzeScripts() {
    console.log("\n📜 ANALYZING SCRIPTS");
    console.log("====================");

    const scripts = [...document.querySelectorAll("script")];
    const analysis = {
      total: scripts.length,
      inline: 0,
      external: 0,
      modules: 0,
      details: [],
      sources: new Set(),
      content: {
        totalSize: 0,
        patterns: {},
      },
    };

    scripts.forEach((script, index) => {
      const detail = {
        index,
        src: script.src,
        type: script.type || "text/javascript",
        async: script.async,
        defer: script.defer,
        module: script.type === "module",
        crossorigin: script.crossOrigin,
        integrity: script.integrity,
        nomodule: script.noModule,
        contentLength: script.textContent.length,
        contentPreview:
          script.textContent.substring(0, 200) +
          (script.textContent.length > 200 ? "..." : ""),
      };

      if (script.src) {
        analysis.external++;
        analysis.sources.add(
          new URL(script.src, window.location.href).hostname,
        );
      } else {
        analysis.inline++;
        analysis.content.totalSize += script.textContent.length;
      }

      if (script.type === "module") {
        analysis.modules++;
      }

      analysis.details.push(detail);
    });

    // Convert Set to Array for serialization
    analysis.sources = [...analysis.sources];

    console.log("Total Scripts:", analysis.total);
    console.log(
      "External:",
      analysis.external,
      "| Inline:",
      analysis.inline,
      "| Modules:",
      analysis.modules,
    );
    console.log("External Sources:", analysis.sources);

    this.results.analysis.scripts = analysis;
  }

  // 7. Stylesheets Analysis
  async analyzeStylesheets() {
    console.log("\n🎨 ANALYZING STYLESHEETS");
    console.log("========================");

    const analysis = {
      links: [],
      inline: [],
      computed: {},
      cssVariables: this.extractCSSVariables(),
      animations: this.extractAnimations(),
      mediaQueries: this.extractMediaQueries(),
    };

    // Analyze link stylesheets
    const linkElements = [
      ...document.querySelectorAll('link[rel="stylesheet"]'),
    ];
    linkElements.forEach((link, index) => {
      analysis.links.push({
        index,
        href: link.href,
        media: link.media,
        crossorigin: link.crossOrigin,
        integrity: link.integrity,
        disabled: link.disabled,
      });
    });

    // Analyze inline styles
    const styleElements = [...document.querySelectorAll("style")];
    styleElements.forEach((style, index) => {
      analysis.inline.push({
        index,
        content:
          style.textContent.substring(0, 300) +
          (style.textContent.length > 300 ? "..." : ""),
        length: style.textContent.length,
        media: style.media,
        disabled: style.disabled,
      });
    });

    console.log("External Stylesheets:", analysis.links.length);
    console.log("Inline Styles:", analysis.inline.length);
    console.log(
      "CSS Variables Found:",
      Object.keys(analysis.cssVariables).length,
    );
    console.log("Animations Found:", analysis.animations.length);

    this.results.analysis.stylesheets = analysis;
  }

  extractCSSVariables() {
    const variables = {};
    const computedStyle = getComputedStyle(document.documentElement);

    // Get CSS custom properties from document element
    for (let property of computedStyle) {
      if (property.startsWith("--")) {
        variables[property] = computedStyle.getPropertyValue(property).trim();
      }
    }

    return variables;
  }

  extractAnimations() {
    const animations = [];

    // Check for CSS animations on all elements
    const allElements = document.querySelectorAll("*");
    allElements.forEach((el) => {
      const computedStyle = getComputedStyle(el);
      const animationName = computedStyle.animationName;
      const transitionProperty = computedStyle.transitionProperty;

      if (animationName && animationName !== "none") {
        animations.push({
          element:
            el.tagName +
            (el.id ? `#${el.id}` : "") +
            (el.className ? `.${[...el.classList].join(".")}` : ""),
          animationName,
          duration: computedStyle.animationDuration,
          timing: computedStyle.animationTimingFunction,
          delay: computedStyle.animationDelay,
          iterationCount: computedStyle.animationIterationCount,
        });
      }

      if (transitionProperty && transitionProperty !== "none") {
        animations.push({
          element:
            el.tagName +
            (el.id ? `#${el.id}` : "") +
            (el.className ? `.${[...el.classList].join(".")}` : ""),
          type: "transition",
          property: transitionProperty,
          duration: computedStyle.transitionDuration,
          timing: computedStyle.transitionTimingFunction,
          delay: computedStyle.transitionDelay,
        });
      }
    });

    return animations.slice(0, 20); // Limit to first 20 to prevent overwhelming output
  }

  extractMediaQueries() {
    const mediaQueries = [];

    [...document.styleSheets].forEach((sheet) => {
      try {
        [...(sheet.cssRules || sheet.rules)].forEach((rule) => {
          if (rule.type === CSSRule.MEDIA_RULE) {
            mediaQueries.push({
              media: rule.media.mediaText,
              rules: rule.cssRules.length,
            });
          }
        });
      } catch (e) {
        // Cross-origin stylesheets can't be accessed
      }
    });

    return mediaQueries;
  }

