  getMetaContent(name) {
    const meta = document.querySelector(
      `meta[name="${name}"], meta[property="${name}"]`,
    );
    return meta ? meta.content : null;
  }

  getOpenGraphData() {
    const ogData = {};
    const ogMetas = document.querySelectorAll('meta[property^="og:"]');

    ogMetas.forEach((meta) => {
      const property = meta.getAttribute("property");
      ogData[property] = meta.content;
    });

    return ogData;
  }

  getTwitterCardData() {
    const twitterData = {};
    const twitterMetas = document.querySelectorAll('meta[name^="twitter:"]');

    twitterMetas.forEach((meta) => {
      const name = meta.getAttribute("name");
      twitterData[name] = meta.content;
    });

    return twitterData;
  }

  getStructuredData() {
    const scripts = document.querySelectorAll(
      'script[type="application/ld+json"]',
    );
    const structuredData = [];

    scripts.forEach((script) => {
      try {
        const data = JSON.parse(script.textContent);
        structuredData.push(data);
      } catch (e) {
        structuredData.push({
          error: "Invalid JSON",
          content: script.textContent.substring(0, 100),
        });
      }
    });

    return structuredData;
  }

  getCanonicalURL() {
    const canonical = document.querySelector('link[rel="canonical"]');
    return canonical ? canonical.href : null;
  }

  getAlternateLanguages() {
    const alternates = document.querySelectorAll(
      'link[rel="alternate"][hreflang]',
    );
    return [...alternates].map((link) => ({
      hreflang: link.hreflang,
      href: link.href,
    }));
  }

  getIcons() {
    const iconLinks = document.querySelectorAll('link[rel*="icon"]');
    return [...iconLinks].map((link) => ({
      rel: link.rel,
      href: link.href,
      type: link.type,
      sizes: link.sizes.toString(),
    }));
  }

