  checkImageAccessibility() {
    const images = [...document.querySelectorAll("img")];
    let withoutAlt = 0;
    let decorative = 0;

    const details = images.map((img) => {
      const hasAlt = img.hasAttribute("alt");
      const altText = img.alt;
      const isDecorative = altText === "";

      if (!hasAlt) withoutAlt++;
      if (isDecorative) decorative++;

      return {
        src: img.src,
        alt: altText,
        hasAlt,
        isDecorative,
        ariaHidden: img.getAttribute("aria-hidden") === "true",
      };
    });

    return {
      total: images.length,
      withoutAlt,
      decorative,
      details: details.slice(0, 20),
    };
  }

  checkHeadingStructure() {
    const headings = [...document.querySelectorAll("h1, h2, h3, h4, h5, h6")];
    const structure = {};

    headings.forEach((heading) => {
      const level = heading.tagName;
      structure[level] = (structure[level] || 0) + 1;
    });

    return {
      total: headings.length,
      structure,
      hasH1: !!document.querySelector("h1"),
      multipleH1: document.querySelectorAll("h1").length > 1,
    };
  }

  checkFormAccessibility() {
    const inputs = [...document.querySelectorAll("input, textarea, select")];
    let withoutLabels = 0;

    const details = inputs.map((input) => {
      const hasLabel = this.hasLabel(input);
      const hasAriaLabel = input.hasAttribute("aria-label");
      const hasAriaLabelledby = input.hasAttribute("aria-labelledby");

      if (!hasLabel && !hasAriaLabel && !hasAriaLabelledby) {
        withoutLabels++;
      }

      return {
        type: input.type || input.tagName,
        id: input.id,
        hasLabel,
        hasAriaLabel,
        hasAriaLabelledby,
        required: input.required,
      };
    });

    return {
      total: inputs.length,
      withoutLabels,
      details: details.slice(0, 20),
    };
  }

  hasLabel(input) {
    // Check for explicit label
    if (input.id) {
      const label = document.querySelector(`label[for="${input.id}"]`);
      if (label) return true;
    }

    // Check for wrapping label
    const parent = input.closest("label");
    return !!parent;
  }

  checkLinkAccessibility() {
    const links = [...document.querySelectorAll("a[href]")];
    let withoutText = 0;

    const details = links.map((link) => {
      const hasText = link.textContent.trim().length > 0;
      const hasAriaLabel = link.hasAttribute("aria-label");
      const hasTitle = link.hasAttribute("title");

      if (!hasText && !hasAriaLabel && !hasTitle) {
        withoutText++;
      }

      return {
        href: link.href,
        text: link.textContent.trim(),
        hasText,
        hasAriaLabel,
        hasTitle,
      };
    });

    return {
      total: links.length,
      withoutText,
      details: details.slice(0, 20),
    };
  }

  checkARIAUsage() {
    const allElements = [...document.querySelectorAll("*")];
    const ariaAttributes = {};
    const roles = {};

    allElements.forEach((el) => {
      [...el.attributes].forEach((attr) => {
        if (attr.name.startsWith("aria-")) {
          ariaAttributes[attr.name] = (ariaAttributes[attr.name] || 0) + 1;
        }
      });

      if (el.hasAttribute("role")) {
        const role = el.getAttribute("role");
        roles[role] = (roles[role] || 0) + 1;
      }
    });

    return {
      attributes: ariaAttributes,
      roles,
      totalElements: Object.values(ariaAttributes).reduce(
        (sum, count) => sum + count,
        0,
      ),
    };
  }

  checkColorContrast() {
    // This is a simplified check - real contrast checking requires color parsing and WCAG calculations
    const elements = [...document.querySelectorAll("*")].slice(0, 100);
    let analyzed = 0;

    elements.forEach((el) => {
      const style = getComputedStyle(el);
      const color = style.color;
      const backgroundColor = style.backgroundColor;

      if (
        color !== "rgba(0, 0, 0, 0)" &&
        backgroundColor !== "rgba(0, 0, 0, 0)"
      ) {
        analyzed++;
      }
    });

    return {
      note: "Full contrast analysis requires specialized tools",
      elementsAnalyzed: analyzed,
    };
  }

  checkLandmarks() {
    const landmarks = [
      "header",
      "nav",
      "main",
      "article",
      "section",
      "aside",
      "footer",
      '[role="banner"]',
      '[role="navigation"]',
      '[role="main"]',
      '[role="article"]',
      '[role="complementary"]',
      '[role="contentinfo"]',
    ];

    const found = {};
    landmarks.forEach((landmark) => {
      const elements = document.querySelectorAll(landmark);
      if (elements.length > 0) {
        found[landmark] = elements.length;
      }
    });

    return found;
  }

  checkFocusableElements() {
    const focusableSelectors = [
      "a[href]",
      "button",
      "input",
      "textarea",
      "select",
      '[tabindex]:not([tabindex="-1"])',
      '[contenteditable="true"]',
    ];

    const focusable = [];
    focusableSelectors.forEach((selector) => {
      const elements = [...document.querySelectorAll(selector)];
      elements.forEach((el) => {
        focusable.push({
          tagName: el.tagName,
          type: el.type || null,
          tabIndex: el.tabIndex,
          disabled: el.disabled || false,
        });
      });
    });

    return {
      total: focusable.length,
      elements: focusable.slice(0, 30),
    };
  }

