                    <h3>${category.charAt(0).toUpperCase() + category.slice(1)}</h3>
                    ${recs.length > 0 ? recs.map(rec => `<div>• ${rec}</div>`).join('') : 'No recommendations'}
                </div>
            `).join('')}
        </div>
    </div>

    <div class="section">
        <h2>Detailed Analysis</h2>
        <pre>${JSON.stringify(this.results.analysis, null, 2)}</pre>
    </div>
</body>
</html>`;
    }
}

